var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다 끝내셨나요, 스승님?","JPN":"師匠、終わりましたか？","ENG":"You done, Master?","TWN":"都結束了嗎，師父？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미리 언질을 듣긴 했지만, 이 정도로 침식체들이 늘어난 걸 보면 정말 상황이 심각하긴 한 모양이네요.","JPN":"聞いてはいましたが、ここまで侵食体が増えてるとは。よほど深刻な状況なんですね。","ENG":"The VP did give us a heads up, but I guess things are getting pretty serious considering the surge in C.O. count.","TWN":"雖然之前就已經聽說了，但侵蝕體竟然增加到這種程度，情況看來非常嚴重。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이래서야 그 조력자라는 분들도 과연 무사하실지 모르겠는데요?","JPN":"これじゃあ助っ人の方々も無事かどうか。","ENG":"I hope those assets are still in one piece.","TWN":"那兩位助手究竟有沒有平安無事呢？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 제자야.","JPN":"なあ、弟子よ。","ENG":"Shiyoon.","TWN":"喂，徒弟。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"왜 그러시죠? 스승님.","JPN":"どうされました、師匠。","ENG":"Yes? Master?","TWN":"師父，怎麼了？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"물어볼 게 있는데......","JPN":"聞きたいことがあるんだが……","ENG":"Let me ask you something...","TWN":"我問你……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희들이 만난 게...... 정말 그 죽은 리플레이서 간부였나?","JPN":"お前たちが会ったのは……本当に、あの死んだリプレイサー幹部だったのか？","ENG":"The hostile you said you encountered... Was it really the dead Replacer officer?","TWN":"你們見到的真的是克隆集團的幹部嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아아, 그거 말인가요?","JPN":"ああ、そのことですか。","ENG":"Oh, that?","TWN":"啊啊，妳說那個嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 정황상 그렇게 보이긴 했습니다.","JPN":"まあ、状況からはそのように見えました。","ENG":"Yeah, it seemed like it at the time.","TWN":"嗯……照當時的情況來看應該是的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......물론 보이는 게 다는 아니겠지만요.","JPN":"……もちろん、目に見えるものがすべてではないでしょうけど。","ENG":"Of course, what we saw might not be everything.","TWN":"……當然，眼見不一定為實。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......역시 그렇군.","JPN":"……やはりそうか。","ENG":"I see...","TWN":"……果然是這樣嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"참 신기하죠? 죽은 사람도 휙휙 살려낼 수 있다니......","JPN":"不思議ですよね、死んだ人もさくっと生き返らせるなんて。","ENG":"Fascinating, huh? They can bring back people from the dead like that...","TWN":"真的很不可思議吧？竟然可以讓死人一個個活過來……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"소문만 무성한 구 관리국에도 그런 기술은 없었을 것 같은데요.","JPN":"噂が一人歩きしている旧管理局でさえ、そんな技術は持っていなかったと思いますが。","ENG":"I bet even the Old Administration didn’t have that sort of technology, despite all the hype.","TWN":"就是傳聞頗多的舊管理局，似乎也沒有這種技術。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그게 아니라면......","JPN":"それとも……","ENG":"Or maybe...","TWN":"如果不是這樣的話……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 이것도 미나 양에게서 추출해 낸 그 신비한 물질의 능력일까요?","JPN":"やっぱりこれも、ミナさんから抽出したというあの神秘的な物質の力なんでしょうか？","ENG":"Could this be from that mysterious substance they extracted from Mina?","TWN":"那這也是從米娜小姐身上提取出來的神秘物質力量囉？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 인자라고 했었나......?","JPN":"クリフォト・ファクターでしたっけ？","ENG":"The Qliphoth Factor, or whatever?","TWN":"是叫逆卡巴拉因子嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 스승님을 처음 만났을 때도 그 비슷한 일이 있었죠.","JPN":"そういえば、師匠に初めて会った時も似たようなことがありましたね。","ENG":"Come to think of it, a similar thing happened when I met you for the first time.","TWN":"這麼說來，我第一次見到師父的時候，也發生了類似的事情。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"예를 들어 제 부모님들에게 일어난 일이라든가......","JPN":"たとえば、僕の両親に起こったこととか……","ENG":"For instance, what happened to my parents...","TWN":"比如說發生在我父母身上的事，還有……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주시윤.","JPN":"シリュウ。","ENG":"Joo Shiyoon.","TWN":"周時雲。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야? 둘 다 모여서 뭘 쑥덕거리고 있는 거야?","JPN":"2人で何をひそひそ話しているの？","ENG":"Huh? What are you two chatting about?","TWN":"幹嘛？你們兩個偷偷摸摸地在說些什麼啊？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 미나 양. 그쪽도 끝났나요?","JPN":"あ、ミナさん。そっちも終わりましたか？","ENG":"Oh, Mina. Are you all done too?","TWN":"……啊，米娜小姐，那邊也結束了嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"끝나긴 했는데......","JPN":"終わってはいるけど……","ENG":"I am, but...","TWN":"嗯，結束是結束了……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"분위기가 왜 이래? 둘이 싸우기라도 했어?","JPN":"なに、この雰囲気。二人でケンカでもしたの？","ENG":"What’s going on here? Did you guys get into a fight?","TWN":"氣氛怎麼怪怪的？你們兩個吵架啦？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 설마요.","JPN":"ハハ、まさか。","ENG":"Haha, of course not.","TWN":"……哈哈，怎麼會呢。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 바보짓으로 날려 버리기엔 제 목숨은 아직 소중하거든요.","JPN":"勝ち目のないケンカをするなんて、そこまで無鉄砲ではないので。","ENG":"I’m not stupid enough to get myself killed like that.","TWN":"我很愛惜生命的，怎麼會做那種傻事呢。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그냥, 스승님께서 미나 양에 대한 걱정이 많으시길래 제가 달래 드리고 있었죠.","JPN":"師匠がミナさんのことをあまりにも心配していたので、僕がなだめていただけです。","ENG":"I was just trying to reassure the Master because she's so worried about you.","TWN":"只是師父很擔心妳，所以我安慰了她幾句。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"걱정? 무슨 걱정......?","JPN":"心配？　何の心配？","ENG":"Worried? About what?","TWN":"擔心？擔心什麼……？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그야 우리가 앞으로 싸워야 할 존재는 <color=#ffd34c>그 리플레이서 비숍</color>으로 추정되는 존재니까요.","JPN":"そりゃあ、僕たちがこれから戦う相手が<color=#ffd34c>リプレイサー・ビショップ</color>だと思われるからです。","ENG":"Well, because it seems that we’re going to have to fight what appears to be <color=#ffd34c>the Replacer Bishop</color>.","TWN":"因為我們推測以後一定會和<color=#ffd34c>克隆·大主教</color>戰鬥。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저희는 상관없지만...... 미나 양은 특별한 사정이 있잖아요?","JPN":"僕たちはかまいませんが、ミナさんは特別な事情がありますからね。","ENG":"Although that hardly makes a difference for us... you have a special history with her, don’t you?","TWN":"我們是無所謂，但米娜小姐不是有特別情況嘛。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 걱정이 되시겠죠.","JPN":"どうしても心配なんでしょう。","ENG":"So I’m sure the Master’s worried about that.","TWN":"再怎麼說也會擔心啊。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......걱정 마.","JPN":"……心配いらないよ。","ENG":"Don’t worry.","TWN":"……別擔心。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배 말대로 죽은 사람이 돌아올 리가 없잖아.","JPN":"先輩の言うとおり、死んだ人が蘇るわけないじゃない。","ENG":"Dead people can’t come back to life. You said so yourself.","TWN":"就像前輩說的，死人是不可能復活的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 나래가 아니야.","JPN":"あれはナルミじゃない。","ENG":"That thing isn’t Narae.","TWN":"那不是娜拉。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 정도는 나도 알고 있다고.","JPN":"それくらい、私にもわかる。","ENG":"I get it too, you know.","TWN":"這種程度的事情我是知道的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......알고 있다니 다행이군.","JPN":"……それならいい。","ENG":"...Good.","TWN":"……妳竟然會知道這種事，我還真是高興呢。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런데 여긴 왜 온 거냐? 보고할 거라도 있나?","JPN":"ところで、なぜここに来た。報告でもあるのか。","ENG":"What brings you here anyway? Got something to report?","TWN":"那妳有什麼事？有什麼要報告的嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 그게......","JPN":"あ、それが……","ENG":"Oh, well...","TWN":"啊，那個……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 조력자인가 뭔가 하는 사람들을 찾은 것 같아.","JPN":"その、助っ人とやらを見つけたっぽいんだけど……","ENG":"I think I found those “assets” they were talking about...","TWN":"我想我找到了那兩個助手還是什麼鬼的人。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래? 그럼 만나봐야겠군. 어디에 있지?","JPN":"そうか、なら会ってみないとな。どこにいるんだ？","ENG":"Is that so? We’d better meet them then. Where are they?","TWN":"是嗎？那我們去看看吧。他們在哪裡？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게.......","JPN":"それが……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 불청객들을 잔뜩 달고 온 것 같아.","JPN":"どうも、招かれざる客をいっぱい連れてきたみたい。","ENG":"It looks like they’ve brought along some unwelcome company.","TWN":"看來他們還招來了很多不速之客。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};